# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient
app = Flask(__name__)
client = MongoClient("mongodb://localhost:27017/")
db = client["user_database"] # assuming that a database named 'user_database' is already created. You can create it if not existent using db = client.get_or_create_database('user_database')
collection = db['users']    # creates collection (tables equivalent) if it doesn't exists

@app.route('/user', methods=['POST'])
def add_user(): 
    data = request.json
    result = collection.insert_one(data) 
    return jsonify({"message": "User added successfully", 'id': str(result.inserted_id)})  

@app.route('/users', methods=['GET'])
def get_all_user():
    all_users = [i for i in collection.find()] # list comprehension to fetch and convert cursor object into a python list of dictionaries
    return jsonify(all_users) 
    
@app.route('/user/<id>', methods=['GET'])
def get_one_user(id): 
    user = collection.find_one({"_id": id}) # finds the document by _id which is inserted as a default while inserting documents into MongoDB
    return jsonify(user)  
    
@app.route('/user/<id>', methods=['DELETE']) 
def delete_user(id): 
    collection.delete_one({"_id": id}) # deletes the document by _id
    return jsonify({"message": "User deleted successfully."})  
    
@app.route('/user/<id>', methods=['PUT'])
def update_user(id): 
    collection.update_one({"_id": id}, {"$set": request.json}) # updates the document by _id with new data sent in the request body
    return jsonify({"message":"User updated successfully."})    
if __name__ == '__main__':  
    app.run(port=5000)